# Category: mfa_bypass

from flask import Flask, request, jsonify, session, redirect, url_for
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import secrets
from functools import wraps
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)
app.config['SESSION_COOKIE_HTTPONLY'] = True
app.config['SESSION_COOKIE_SAMESITE'] = 'Lax'

users_db = {
    'user1': {
        'password_hash': generate_password_hash('password123'),
        'mfa_secret': pyotp.random_base32(),
        'mfa_verified': False
    },
    'user2': {
        'password_hash': generate_password_hash('securepass'),
        'mfa_secret': pyotp.random_base32(),
        'mfa_verified': False
    }
}

mfa_pending = {}

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        return f(*args, **kwargs)
    return decorated_function

def full_auth_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        
        username = session['username']
        if username in mfa_pending:
            pending_time = mfa_pending[username]
            if datetime.now() - pending_time > timedelta(minutes=5):
                session.pop('username', None)
                mfa_pending.pop(username, None)
                return jsonify({'error': 'MFA verification timeout'}), 401
            return jsonify({'error': 'MFA verification required', 'redirect': '/verify-mfa'}), 403
        
        return f(*args, **kwargs)
    return decorated_function

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    if username not in users_db:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    user = users_db[username]
    
    if not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    session['username'] = username
    mfa_pending[username] = datetime.now()
    
    return jsonify({
        'message': 'Login successful',
        'redirect': '/verify-mfa',
        'mfa_required': True
    }), 200

@app.route('/verify-mfa', methods=['GET', 'POST'])
@login_required
def verify_mfa():
    username = session['username']
    
    if request.method == 'GET':
        if username not in mfa_pending:
            return jsonify({'message': 'MFA already verified'}), 200
        
        user = users_db[username]
        totp = pyotp.TOTP(user['mfa_secret'])
        
        return jsonify({
            'message': 'MFA verification required',
            'qr_provisioning_uri': totp.provisioning_uri(username, issuer_name='MyApp'),
            'secret': user['mfa_secret']
        }), 200
    
    if request.method == 'POST':
        data = request.get_json()
        mfa_code = data.get('mfa_code')
        
        if not mfa_code:
            return jsonify({'error': 'MFA code required'}), 400
        
        user = users_db[username]
        totp = pyotp.TOTP(user['mfa_secret'])
        
        if totp.verify(mfa_code, valid_window=1):
            mfa_pending.pop(username, None)
            users_db[username]['mfa_verified'] = True
            return jsonify({'message': 'MFA verified successfully'}), 200
        else:
            return jsonify({'error': 'Invalid MFA code'}), 401

@app.route('/protected-resource', methods=['GET'])
@login_required
def protected_resource():
    username = session['username']
    mfa_status = 'pending' if username in mfa_pending else 'verified'
    
    return jsonify({
        'message': 'Access granted to protected resource',
        'username': username,
        'mfa_status': mfa_status,
        'data': 'This is protected data'
    }), 200

@app.route('/fully-protected-resource', methods=['GET'])
@full_auth_required
def fully_protected_resource():
    username = session['username']
    
    return jsonify({
        'message': 'Access granted to fully protected resource',
        'username': username,
        'data': 'This is highly sensitive data'
    }), 200

@app.route('/logout', methods=['POST'])
def logout():
    username = session.get('username')
    if username:
        mfa_pending.pop(username, None)
    session.clear()
    return jsonify({'message': 'Logged out successfully'}), 200

@app.route('/status', methods=['GET'])
@login_required
def status():
    username = session['username']
    mfa_status = 'pending' if username in mfa_pending else 'verified'
    
    return jsonify({
        'username': username,
        'logged_in': True,
        'mfa_status': mfa_status
    }), 200

